"""Ansible Network Automation — Knowledge Lab"""
import json

try:
    import yaml
    HAS_YAML = True
except ImportError:
    HAS_YAML = False

try:
    from jinja2 import Template
    HAS_JINJA2 = True
except ImportError:
    HAS_JINJA2 = False

def print_yaml(data):
    """Print data as YAML if available, otherwise as formatted JSON."""
    if HAS_YAML:
        print(yaml.dump(data, default_flow_style=False, sort_keys=False).rstrip())
    else:
        print(json.dumps(data, indent=2))

# ============================================
# Task 1: Build an Inventory
# ============================================
print("=== Task 1: Create Inventory ===")

inventory = {
    "groups": {
        "routers": {
            "hosts": {
                "R1": {"ansible_host": "10.0.0.1"},
                "R2": {"ansible_host": "10.0.0.2"},
            },
            "vars": {
                "ansible_network_os": "cisco.ios.ios",
                "ansible_connection": "ansible.netcommon.network_cli",
                "ansible_user": "admin",
            },
        },
        "switches": {
            "hosts": {
                "SW1": {"ansible_host": "10.0.0.10"},
            },
            "vars": {
                "ansible_network_os": "cisco.ios.ios",
                "ansible_connection": "ansible.netcommon.network_cli",
                "ansible_user": "admin",
            },
        },
    },
}

# Print in INI format
for group_name, group in inventory["groups"].items():
    print(f"[{group_name}]")
    for host, hvars in group["hosts"].items():
        vars_str = " ".join(f"{k}={v}" for k, v in hvars.items())
        print(f"{host} {vars_str}")
    print()

print("[network:children]")
for group_name in inventory["groups"]:
    print(group_name)
print()

for group_name, group in inventory["groups"].items():
    if group["vars"]:
        print(f"[{group_name}:vars]")
        for k, v in group["vars"].items():
            print(f"{k}={v}")
        print()

# ============================================
# Task 2: Facts-Gathering Playbook
# ============================================
print("=== Task 2: Facts Playbook ===")

facts_playbook = [
    {
        "name": "Gather Network Device Facts",
        "hosts": "routers",
        "gather_facts": False,
        "tasks": [
            {
                "name": "Gather IOS facts",
                "cisco.ios.ios_facts": {
                    "gather_subset": ["all"],
                },
            },
            {
                "name": "Display device hostname",
                "ansible.builtin.debug": {
                    "msg": "Hostname: {{ ansible_net_hostname }}",
                },
            },
            {
                "name": "Display OS version",
                "ansible.builtin.debug": {
                    "msg": "Version: {{ ansible_net_version }}",
                },
            },
            {
                "name": "Display interfaces",
                "ansible.builtin.debug": {
                    "msg": "Interfaces: {{ ansible_net_interfaces.keys() | list }}",
                },
            },
        ],
    }
]

print_yaml(facts_playbook)

print()

# ============================================
# Task 3: Configuration Playbook
# ============================================
print("=== Task 3: Config Playbook ===")

config_playbook = [
    {
        "name": "Configure Network Devices",
        "hosts": "routers",
        "gather_facts": False,
        "vars": {
            "ntp_server": "198.51.100.1",
            "dns_server": "198.51.100.53",
            "syslog_server": "198.51.100.10",
        },
        "tasks": [
            {
                "name": "Configure NTP server",
                "cisco.ios.ios_config": {
                    "lines": ["ntp server {{ ntp_server }}"],
                },
            },
            {
                "name": "Configure DNS",
                "cisco.ios.ios_config": {
                    "lines": [
                        "ip name-server {{ dns_server }}",
                        "ip domain-lookup",
                    ],
                },
            },
            {
                "name": "Configure syslog",
                "cisco.ios.ios_config": {
                    "lines": ["logging host {{ syslog_server }}"],
                },
                "notify": "Save Configuration",
            },
            {
                "name": "Configure SSH on VTY lines",
                "cisco.ios.ios_config": {
                    "parents": "line vty 0 4",
                    "lines": [
                        "transport input ssh",
                        "login local",
                        "exec-timeout 15 0",
                    ],
                },
            },
        ],
        "handlers": [
            {
                "name": "Save Configuration",
                "cisco.ios.ios_command": {
                    "commands": ["write memory"],
                },
            },
        ],
    }
]

print_yaml(config_playbook)

print()

# ============================================
# Task 4: Jinja2 Template
# ============================================
print("=== Task 4: Jinja2 Template ===")

template_str = """! Generated by Ansible
!
hostname {{ hostname }}
!
{% for intf in interfaces %}
interface {{ intf.name }}
 description {{ intf.description }}
 ip address {{ intf.ip }} {{ intf.mask }}
{% if intf.enabled %}
 no shutdown
{% else %}
 shutdown
{% endif %}
!
{% endfor %}
{% if ospf is defined and ospf %}
router ospf {{ ospf.process_id }}
{% for net in ospf.networks %}
 network {{ net.address }} {{ net.wildcard }} area {{ net.area }}
{% endfor %}
{% endif %}
!
end"""

host_vars = {
    "hostname": "R1",
    "interfaces": [
        {"name": "GigabitEthernet0/0", "description": "WAN Uplink",
         "ip": "10.0.0.1", "mask": "255.255.255.0", "enabled": True},
        {"name": "GigabitEthernet0/1", "description": "LAN Segment",
         "ip": "10.0.1.1", "mask": "255.255.255.0", "enabled": True},
        {"name": "Loopback0", "description": "Router ID",
         "ip": "1.1.1.1", "mask": "255.255.255.255", "enabled": True},
    ],
    "ospf": {
        "process_id": 1,
        "networks": [
            {"address": "10.0.0.0", "wildcard": "0.0.0.255", "area": 0},
            {"address": "10.0.1.0", "wildcard": "0.0.0.255", "area": 0},
            {"address": "1.1.1.1", "wildcard": "0.0.0.0", "area": 0},
        ],
    },
}

if HAS_JINJA2:
    template = Template(template_str)
    rendered = template.render(**host_vars)
    print("Rendered router configuration:")
    print(rendered)
else:
    # Manual rendering fallback
    print("Rendered router configuration:")
    print("! Generated by Ansible")
    print("!")
    print(f"hostname {host_vars['hostname']}")
    print("!")
    for intf in host_vars["interfaces"]:
        print(f"interface {intf['name']}")
        print(f" description {intf['description']}")
        print(f" ip address {intf['ip']} {intf['mask']}")
        print(" no shutdown" if intf["enabled"] else " shutdown")
        print("!")
    ospf = host_vars["ospf"]
    print(f"router ospf {ospf['process_id']}")
    for net in ospf["networks"]:
        print(f" network {net['address']} {net['wildcard']} area {net['area']}")
    print("!")
    print("end")

print()

# ============================================
# Task 5: Interpret Workflow
# ============================================
print("=== Task 5: Interpret Workflow ===")

workflow = [
    {
        "play": "Pre-change Validation",
        "hosts": "routers",
        "tasks": [
            "Check current OSPF neighbors (show ip ospf neighbor)",
            "Save pre-change state to local file",
        ],
        "purpose": "Captures baseline state before making any changes",
    },
    {
        "play": "Apply Configuration Changes",
        "hosts": "routers",
        "tasks": [
            "Apply OSPF config from Jinja2 template (ios_config src=)",
            "Handler: Save config (write memory) on change",
        ],
        "purpose": "Pushes the new configuration to devices",
    },
    {
        "play": "Post-change Validation",
        "hosts": "routers",
        "tasks": [
            "Wait 30 seconds for OSPF convergence",
            "Check OSPF neighbors after change",
            "Assert OSPF neighbors are in FULL state",
        ],
        "purpose": "Verifies the change was successful and routing converged",
    },
]

for i, play in enumerate(workflow, 1):
    print(f"Play {i}: {play['play']}")
    print(f"  Hosts: {play['hosts']}")
    print(f"  Tasks:")
    for task in play["tasks"]:
        print(f"    - {task}")
    print(f"  Purpose: {play['purpose']}")
    print()

print("Workflow Pattern: Validate -> Change -> Validate")
print("This is the standard approach for safe network automation.")
print("If post-validation fails, the pre-change state enables rollback.")
print()
print("Lab complete!")
